    out << "struct np_json_parser_t {\n";
    out << "    std::string src;\n";
    out << "    size_t pos = 0;\n";
    out << "    void skip_whitespace() {\n";
    out << "        while (pos < src.size() && (src[pos] == ' ' || src[pos] == '\\t' || src[pos] == '\\n' || src[pos] == '\\r')) pos++;\n";
    out << "    }\n";
    out << "    char peek() {\n";
    out << "        skip_whitespace();\n";
    out << "        if (pos >= src.size()) return '\\0';\n";
    out << "        return src[pos];\n";
    out << "    }\n";
    out << "    char get() {\n";
    out << "        skip_whitespace();\n";
    out << "        if (pos >= src.size()) return '\\0';\n";
    out << "        return src[pos++];\n";
    out << "    }\n";
    out << "    np_var parse_value() {\n";
    out << "        char c = peek();\n";
    out << "        if (c == '{') return parse_object();\n";
    out << "        if (c == '[') return parse_array();\n";
    out << "        if (c == '\"') return parse_string();\n";
    out << "        if (c == 't' || c == 'f') return parse_bool();\n";
    out << "        if (c == 'n') { pos += 4; return np_var(); }\n";
    out << "        if ((c >= '0' && c <= '9') || c == '-') return parse_number();\n";
    out << "        return np_var();\n";
    out << "    }\n";
    out << "    np_var parse_object() {\n";
    out << "        get(); // '{'\n";
    out << "        std::map<std::string, np_var> obj;\n";
    out << "        if (peek() == '}') { get(); return np_var(obj); }\n";
    out << "        while (true) {\n";
    out << "            np_var key_var = parse_string();\n";
    out << "            std::string key = static_cast<std::string>(key_var);\n";
    out << "            if (get() != ':') return np_var(obj);\n";
    out << "            np_var val = parse_value();\n";
    out << "            obj[key] = val;\n";
    out << "            char c = peek();\n";
    out << "            if (c == '}') { get(); break; }\n";
    out << "            if (c == ',') get();\n";
    out << "            else break;\n";
    out << "        }\n";
    out << "        return np_var(obj);\n";
    out << "    }\n";
    out << "    np_var parse_array() {\n";
    out << "        get(); // '['\n";
    out << "        std::vector<np_var> arr;\n";
    out << "        if (peek() == ']') { get(); return np_var(arr); }\n";
    out << "        while (true) {\n";
    out << "            arr.push_back(parse_value());\n";
    out << "            char c = peek();\n";
    out << "            if (c == ']') { get(); break; }\n";
    out << "            if (c == ',') get();\n";
    out << "            else break;\n";
    out << "        }\n";
    out << "        return np_var(arr);\n";
    out << "    }\n";
    out << "    np_var parse_string() {\n";
    out << "        get(); // '\"'\n";
    out << "        std::string s = \"\";\n";
    out << "        while (pos < src.size()) {\n";
    out << "            char c = src[pos++];\n";
    out << "            if (c == '\"') break;\n";
    out << "            if (c == '\\\\' && pos < src.size()) {\n";
    out << "                char next = src[pos++];\n";
    out << "                if (next == '\"') s += '\"';\n";
    out << "                else if (next == '\\\\') s += '\\\\';\n";
    out << "                else if (next == 'n') s += '\\n';\n";
    out << "                else if (next == 't') s += '\\t';\n";
    out << "                else if (next == 'r') s += '\\r';\n";
    out << "                else s += next;\n";
    out << "            } else {\n";
    out << "                s += c;\n";
    out << "            }\n";
    out << "        }\n";
    out << "        return np_var(s);\n";
    out << "    }\n";
    out << "    np_var parse_bool() {\n";
    out << "        if (peek() == 't') { pos += 4; return np_var(true); }\n";
    out << "        else { pos += 5; return np_var(false); }\n";
    out << "        return np_var();\n";
