    out << "            if ((c >= '0' && c <= '9') || c == '-' || c == '+' || c == 'e' || c == 'E') pos++;\n";
    out << "            else if (c == '.') { is_double = true; pos++; }\n";
    out << "            else break;\n";
    out << "        }\n";
    out << "        std::string num_str = src.substr(start, pos - start);\n";
    out << "        if (is_double) {\n";
    out << "            try { return np_var(std::stod(num_str)); } catch(...) { return np_var(0.0); }\n";
    out << "        } else {\n";
    out << "            try { return np_var(static_cast<int64_t>(std::stoll(num_str))); } catch(...) { return np_var(static_cast<int64_t>(0)); }\n";
    out << "        }\n";
    out << "    }\n";
    out << "};\n";
    out << "inline np_var np_json_parse(const std::string& src) {\n";
    out << "    np_json_parser_t parser;\n";
    out << "    parser.src = src;\n";
    out << "    return parser.parse_value();\n";
    out << "}\n";
    out << "inline np_var np_json_parse(const np_var& src) {\n";
    out << "    return np_json_parse(static_cast<std::string>(src));\n";
    out << "}\n";
    out << "inline bool np_regex_match(const std::string& pattern, const std::string& text) {\n";
    out << "    try { std::regex re(pattern); return std::regex_match(text, re); } catch(...) { return false; }\n";
    out << "}\n";
    out << "inline bool np_regex_match(const np_var& pattern, const np_var& text) {\n";
    out << "    return np_regex_match(static_cast<std::string>(pattern), static_cast<std::string>(text));\n";
    out << "}\n";
    out << "inline std::string np_regex_find(const std::string& pattern, const std::string& text) {\n";
    out << "    try {\n";
    out << "        std::regex re(pattern); std::smatch m; \n";
    out << "        if (std::regex_search(text, m, re)) return m.str(0);\n";
    out << "    } catch(...) {}\n";
    out << "    return \"\";\n";
    out << "}\n";
    out << "inline std::string np_regex_find(const np_var& pattern, const np_var& text) {\n";
    out << "    return np_regex_find(static_cast<std::string>(pattern), static_cast<std::string>(text));\n";
    out << "}\n";
    out << "inline std::string np_regex_replace(const std::string& pattern, const std::string& repl, const std::string& text) {\n";
    out << "    try { std::regex re(pattern); return std::regex_replace(text, re, repl); } catch(...) { return text; }\n";
    out << "}\n";
    out << "inline std::string np_regex_replace(const np_var& pattern, const np_var& repl, const np_var& text) {\n";
    out << "    return np_regex_replace(static_cast<std::string>(pattern), static_cast<std::string>(repl), static_cast<std::string>(text));\n";
